using System;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;

public class Event
{
    public int Id { get; set; }
    public int AvailableSeats { get; set; }
}

public class TicketService
{
    private readonly DbContext _context;

    public TicketService(DbContext context)
    {
        _context = context;
    }

    public async Task<bool> PurchaseTickets(int eventId, int quantity)
    {
        using(var transaction = await _context.Database.BeginTransactionAsync())
        {
            var eventEntity = await _context.FindAsync<Event>(eventId);
            
            if(eventEntity == null)
            {
               throw new Exception("Event not found");
            }
            
            if(eventEntity.AvailableSeats < quantity) // Check Available Seats
            {
                return false;
            }

            eventEntity.AvailableSeats -= quantity; // Update Inventory
            _context.Update(eventEntity);
            
            try
            {
                await _context.SaveChangesAsync();
                await transaction.CommitAsync();
                
                return true;
            }
            catch(DbUpdateConcurrencyException)
            {
                return false;
            }
        }
    }
}